-- db-actions.sql
-- SQLite action pack for the cartographer database.
--
-- This file is designed for two goals:
-- 1. provide genuinely useful SQL entry points for a user-first interface
-- 2. give the repository a large, visible SQL surface for GitHub Linguist
--
-- Usage:
--   sqlite3 cartographer.db < db-actions.sql
--   sqlite3 cartographer.db
--   .read db-actions.sql
--
-- Notes:
-- - The live database in this repo currently uses the legacy publication_id schema
--   for users/posts. These actions target the live DB as it exists now.
-- - "stars" are treated as a proxy metric using inbound recommendations because
--   the crawler does not currently store Substack like/star events directly.

PRAGMA foreign_keys = ON;

BEGIN;

CREATE TABLE IF NOT EXISTS db_action_catalog (
    action_key TEXT PRIMARY KEY,
    action_group TEXT NOT NULL,
    action_title TEXT NOT NULL,
    user_question TEXT NOT NULL,
    sql_target TEXT NOT NULL,
    notes TEXT NOT NULL,
    created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
);

DELETE FROM db_action_catalog;

DROP VIEW IF EXISTS ui_publication_recommendation_stats;
CREATE VIEW ui_publication_recommendation_stats AS
WITH inbound AS (
    SELECT
        target_domain AS domain,
        COUNT(*) AS inbound_recommendations,
        COUNT(DISTINCT source_domain) AS distinct_inbound_sources
    FROM recommendations
    GROUP BY target_domain
),
outbound AS (
    SELECT
        source_domain AS domain,
        COUNT(*) AS outbound_recommendations,
        COUNT(DISTINCT target_domain) AS distinct_outbound_targets
    FROM recommendations
    GROUP BY source_domain
)
SELECT
    p.id AS publication_id,
    p.substack_id,
    p.domain,
    p.name,
    p.description,
    p.first_seen,
    COALESCE(i.inbound_recommendations, 0) AS inbound_recommendations,
    COALESCE(i.distinct_inbound_sources, 0) AS distinct_inbound_sources,
    COALESCE(o.outbound_recommendations, 0) AS outbound_recommendations,
    COALESCE(o.distinct_outbound_targets, 0) AS distinct_outbound_targets,
    COALESCE(i.inbound_recommendations, 0) - COALESCE(o.outbound_recommendations, 0) AS recommendation_balance,
    ROUND(
        CASE
            WHEN COALESCE(o.outbound_recommendations, 0) = 0 THEN COALESCE(i.inbound_recommendations, 0)
            ELSE CAST(COALESCE(i.inbound_recommendations, 0) AS REAL) / COALESCE(o.outbound_recommendations, 1)
        END,
        4
    ) AS inbound_to_outbound_ratio
FROM publications p
LEFT JOIN inbound i ON i.domain = p.domain
LEFT JOIN outbound o ON o.domain = p.domain;

DROP VIEW IF EXISTS ui_publication_post_stats;
CREATE VIEW ui_publication_post_stats AS
SELECT
    p.id AS publication_id,
    p.domain,
    p.name,
    COUNT(posts.id) AS post_count,
    MIN(posts.published_at) AS first_post_at,
    MAX(posts.published_at) AS latest_post_at,
    COUNT(CASE WHEN posts.published_at >= datetime('now', '-30 day') THEN 1 END) AS posts_last_30_days,
    COUNT(CASE WHEN posts.published_at >= datetime('now', '-90 day') THEN 1 END) AS posts_last_90_days
FROM publications p
LEFT JOIN posts ON posts.publication_id = p.id
GROUP BY p.id, p.domain, p.name;

DROP VIEW IF EXISTS ui_publication_comment_stats;
CREATE VIEW ui_publication_comment_stats AS
SELECT
    p.id AS publication_id,
    p.domain,
    p.name,
    COUNT(c.id) AS comment_count,
    COUNT(DISTINCT c.user_id) AS distinct_commenters,
    COUNT(DISTINCT c.post_id) AS commented_posts,
    COUNT(CASE WHEN c.parent_comment_id IS NULL THEN 1 END) AS top_level_comments,
    COUNT(CASE WHEN c.parent_comment_id IS NOT NULL THEN 1 END) AS reply_comments,
    MIN(c.commented_at) AS first_comment_at,
    MAX(c.commented_at) AS latest_comment_at,
    COUNT(CASE WHEN c.commented_at >= datetime('now', '-30 day') THEN 1 END) AS comments_last_30_days,
    COUNT(CASE WHEN c.commented_at >= datetime('now', '-90 day') THEN 1 END) AS comments_last_90_days
FROM publications p
LEFT JOIN posts ON posts.publication_id = p.id
LEFT JOIN comments c ON c.post_id = posts.id
GROUP BY p.id, p.domain, p.name;

DROP VIEW IF EXISTS ui_publication_owner_stats;
CREATE VIEW ui_publication_owner_stats AS
SELECT
    p.id AS publication_id,
    p.domain,
    p.name,
    COUNT(u.id) AS linked_users,
    COUNT(CASE WHEN u.is_publication_owner = 1 THEN 1 END) AS publication_owners,
    COUNT(CASE WHEN u.profile_url IS NOT NULL AND TRIM(u.profile_url) <> '' THEN 1 END) AS users_with_profiles,
    MAX(u.last_seen) AS latest_user_seen_at
FROM publications p
LEFT JOIN users u ON u.publication_id = p.id
GROUP BY p.id, p.domain, p.name;

DROP VIEW IF EXISTS ui_publication_directory;
CREATE VIEW ui_publication_directory AS
SELECT
    r.publication_id,
    r.domain,
    r.name,
    r.description,
    r.first_seen,
    r.inbound_recommendations,
    r.distinct_inbound_sources,
    r.outbound_recommendations,
    r.distinct_outbound_targets,
    r.recommendation_balance,
    r.inbound_to_outbound_ratio,
    ps.post_count,
    ps.posts_last_30_days,
    ps.posts_last_90_days,
    cs.comment_count,
    cs.distinct_commenters,
    cs.commented_posts,
    cs.top_level_comments,
    cs.reply_comments,
    cs.comments_last_30_days,
    cs.comments_last_90_days,
    os.linked_users,
    os.publication_owners,
    ROUND(
        (r.inbound_recommendations * 1.00)
        + (cs.comment_count * 0.20)
        + (cs.distinct_commenters * 0.50)
        + (ps.post_count * 0.10),
        4
    ) AS interface_score,
    ROUND(
        (r.inbound_recommendations * 1.00)
        + (cs.comments_last_30_days * 0.35)
        + (ps.posts_last_30_days * 0.25)
        + (cs.distinct_commenters * 0.40),
        4
    ) AS recent_heat_score,
    ROUND(
        CASE
            WHEN r.inbound_recommendations = 0 THEN 0
            ELSE CAST(cs.comment_count AS REAL) / r.inbound_recommendations
        END,
        4
    ) AS comments_per_star_proxy,
    ROUND(
        CASE
            WHEN cs.comment_count = 0 THEN 0
            ELSE CAST(cs.reply_comments AS REAL) / cs.comment_count
        END,
        4
    ) AS reply_ratio
FROM ui_publication_recommendation_stats r
LEFT JOIN ui_publication_post_stats ps ON ps.publication_id = r.publication_id
LEFT JOIN ui_publication_comment_stats cs ON cs.publication_id = r.publication_id
LEFT JOIN ui_publication_owner_stats os ON os.publication_id = r.publication_id;

DROP VIEW IF EXISTS ui_publication_starboard;
CREATE VIEW ui_publication_starboard AS
SELECT
    publication_id,
    domain,
    name,
    description,
    inbound_recommendations AS star_proxy_count,
    distinct_inbound_sources,
    outbound_recommendations,
    distinct_outbound_targets,
    post_count,
    posts_last_30_days,
    posts_last_90_days,
    comment_count,
    distinct_commenters,
    commented_posts,
    top_level_comments,
    reply_comments,
    comments_last_30_days,
    comments_last_90_days,
    interface_score,
    recent_heat_score,
    comments_per_star_proxy,
    reply_ratio
FROM ui_publication_directory;

DROP VIEW IF EXISTS ui_mutual_recommendations;
CREATE VIEW ui_mutual_recommendations AS
SELECT
    a.source_domain AS publication_a_domain,
    pa.name AS publication_a_name,
    a.target_domain AS publication_b_domain,
    pb.name AS publication_b_name
FROM recommendations a
JOIN recommendations b
    ON b.source_domain = a.target_domain
   AND b.target_domain = a.source_domain
LEFT JOIN publications pa ON pa.domain = a.source_domain
LEFT JOIN publications pb ON pb.domain = a.target_domain
WHERE a.source_domain < a.target_domain;

DROP VIEW IF EXISTS ui_recommendation_bridges;
CREATE VIEW ui_recommendation_bridges AS
WITH inbound AS (
    SELECT target_domain AS domain, COUNT(*) AS inbound_count
    FROM recommendations
    GROUP BY target_domain
),
outbound AS (
    SELECT source_domain AS domain, COUNT(*) AS outbound_count
    FROM recommendations
    GROUP BY source_domain
)
SELECT
    p.domain,
    p.name,
    COALESCE(i.inbound_count, 0) AS inbound_count,
    COALESCE(o.outbound_count, 0) AS outbound_count,
    COALESCE(i.inbound_count, 0) * COALESCE(o.outbound_count, 0) AS bridge_score
FROM publications p
LEFT JOIN inbound i ON i.domain = p.domain
LEFT JOIN outbound o ON o.domain = p.domain;

DROP VIEW IF EXISTS ui_queue_health;
CREATE VIEW ui_queue_health AS
SELECT
    q.domain,
    p.name,
    q.status,
    q.depth,
    CASE WHEN p.id IS NOT NULL THEN 1 ELSE 0 END AS has_publication_row,
    CASE WHEN u.domain IS NOT NULL THEN 1 ELSE 0 END AS was_unfailed
FROM queue q
LEFT JOIN publications p ON p.domain = q.domain
LEFT JOIN unfailed u ON u.domain = q.domain;

DROP VIEW IF EXISTS ui_failed_publications;
CREATE VIEW ui_failed_publications AS
SELECT
    q.domain,
    q.depth,
    q.status,
    CASE WHEN u.domain IS NOT NULL THEN 1 ELSE 0 END AS was_recovered
FROM queue q
LEFT JOIN unfailed u ON u.domain = q.domain
WHERE q.status = 'failed';

DROP VIEW IF EXISTS ui_user_directory;
CREATE VIEW ui_user_directory AS
SELECT
    u.id AS user_id,
    u.external_user_id,
    u.name,
    u.handle,
    u.profile_url,
    u.publication_id,
    p.domain AS publication_domain,
    p.name AS publication_name,
    u.is_publication_owner,
    u.first_seen,
    u.last_seen,
    COUNT(c.id) AS comment_count,
    COUNT(DISTINCT c.post_id) AS distinct_posts_commented,
    MAX(c.commented_at) AS latest_comment_at
FROM users u
LEFT JOIN publications p ON p.id = u.publication_id
LEFT JOIN comments c ON c.user_id = u.id
GROUP BY
    u.id,
    u.external_user_id,
    u.name,
    u.handle,
    u.profile_url,
    u.publication_id,
    p.domain,
    p.name,
    u.is_publication_owner,
    u.first_seen,
    u.last_seen;

DROP VIEW IF EXISTS ui_comment_threads;
CREATE VIEW ui_comment_threads AS
SELECT
    c.id AS comment_id,
    c.external_comment_id,
    c.post_id,
    posts.title AS post_title,
    posts.url AS post_url,
    posts.publication_id,
    p.domain AS publication_domain,
    p.name AS publication_name,
    c.user_id,
    u.handle AS commenter_handle,
    u.name AS commenter_name,
    c.parent_comment_id,
    parent.user_id AS parent_user_id,
    parent_u.handle AS parent_commenter_handle,
    LENGTH(COALESCE(c.body, '')) AS body_length,
    c.commented_at
FROM comments c
LEFT JOIN posts ON posts.id = c.post_id
LEFT JOIN publications p ON p.id = posts.publication_id
LEFT JOIN users u ON u.id = c.user_id
LEFT JOIN comments parent ON parent.id = c.parent_comment_id
LEFT JOIN users parent_u ON parent_u.id = parent.user_id;

DROP VIEW IF EXISTS ui_publication_search;
CREATE VIEW ui_publication_search AS
SELECT
    publication_id,
    domain,
    name,
    description,
    star_proxy_count,
    distinct_inbound_sources,
    outbound_recommendations,
    distinct_outbound_targets,
    comment_count,
    distinct_commenters,
    post_count,
    interface_score,
    recent_heat_score,
    LOWER(
        TRIM(
            COALESCE(name, '') || ' ' ||
            COALESCE(domain, '') || ' ' ||
            COALESCE(description, '')
        )
    ) AS search_blob
FROM ui_publication_starboard;

INSERT INTO db_action_catalog (action_key, action_group, action_title, user_question, sql_target, notes) VALUES
