('bridge_publications', 'network', 'Bridge Publications', 'Which publications connect many parts of the network?', 'ui_recommendation_bridges', 'Bridge score multiplies inbound and outbound recommendation counts.'),
('mutual_pairs', 'network', 'Mutual Recommendation Pairs', 'Which publications recommend each other?', 'ui_mutual_recommendations', 'Useful for two-way affinity or co-sign patterns.'),
('queue_health', 'operations', 'Queue Health', 'What is the crawler waiting on or failing on?', 'ui_queue_health', 'Tracks crawl state, publication existence, and unfailed recovery.'),
('failed_publications', 'operations', 'Failed Publications', 'Which publication domains are failing?', 'ui_failed_publications', 'Prioritize low-depth failures first.'),
('top_commenters', 'community', 'Top Commenters', 'Who comments the most?', 'ui_user_directory', 'Ranks commenters by total comments and breadth across posts.'),
