COMMIT;

/*
Query recipes (copy/paste as needed):

001. Which publications get a lot of stars?
SELECT domain, name, star_proxy_count, distinct_inbound_sources, recent_heat_score, interface_score
FROM ui_publication_starboard
ORDER BY star_proxy_count DESC, recent_heat_score DESC
LIMIT 50;

002. Which publications look underrated?
SELECT domain, name, star_proxy_count, comment_count, distinct_commenters, comments_per_star_proxy, recent_heat_score
FROM ui_publication_directory
WHERE star_proxy_count BETWEEN 3 AND 150
ORDER BY comments_per_star_proxy DESC, distinct_commenters DESC, recent_heat_score DESC
LIMIT 50;

003. Which publications are hottest in the last 30 days?
SELECT domain, name, posts_last_30_days, comments_last_30_days, star_proxy_count, recent_heat_score
FROM ui_publication_starboard
ORDER BY recent_heat_score DESC, comments_last_30_days DESC, posts_last_30_days DESC
LIMIT 50;

004. Which publications combine stars proxy with actual discussion?
SELECT domain, name, star_proxy_count, comment_count, distinct_commenters, reply_ratio, recent_heat_score
FROM ui_publication_starboard
ORDER BY star_proxy_count DESC, comment_count DESC, distinct_commenters DESC
LIMIT 50;

005. Search publications for a UI search box.
SELECT domain, name, description, star_proxy_count, recent_heat_score
FROM ui_publication_search
WHERE search_blob LIKE '%' || LOWER('economics') || '%'
ORDER BY recent_heat_score DESC, star_proxy_count DESC
LIMIT 50;
*/

