-- action_catalog_0331 | group=discovery | surface=underrated shelf | prompt=Which publications deserve a hidden gems module because they outperform their hype? | filter_note=only rows with recent_heat_score > 0 for trending surfaces | ranking_note=default sort should stay descending by the main score with a stable domain tiebreaker | ux_note=biasing slightly toward recent motion instead of only all-time totals | sql=SELECT domain, name, comments_per_star_proxy, comment_count, distinct_commenters FROM ui_publication_directory WHERE inbound_recommendations BETWEEN 2 AND 150 ORDER BY comments_per_star_proxy DESC, distinct_commenters DESC LIMIT 25;
-- action_catalog_0332 | group=network | surface=bridge finder | prompt=Which publications seem to generate the most community energy per recommendation? | filter_note=only rows where description is not null when a UI card needs copy | ranking_note=secondary sort should prefer recent_heat_score so stale giants do not always win | ux_note=keeping enough metadata visible for a card-based interface | sql=SELECT domain, name, bridge_score, inbound_count, outbound_count FROM ui_recommendation_bridges ORDER BY bridge_score DESC, inbound_count DESC LIMIT 25;
