-- action_catalog_0586 | group=heat | surface=trending rail | prompt=What should the homepage show if a user wants the safest high-signal starting points? | filter_note=only rows with star_proxy_count >= 5 when the action is star-oriented | ranking_note=secondary sort should prefer bridge_score when discovery and navigation matter | ux_note=favoring approachable publications over edge-case operators | sql=SELECT domain, name, recent_heat_score, posts_last_30_days, comments_last_30_days FROM ui_publication_directory ORDER BY recent_heat_score DESC, inbound_recommendations DESC LIMIT 25;
