-- action_catalog_0995 | group=discovery | surface=underrated shelf | prompt=Which publications deserve a hidden gems module because they outperform their hype? | filter_note=only rows with recent_heat_score > 0 for trending surfaces | ranking_note=secondary sort should prefer comments_per_star_proxy when hunting for underrated communities | ux_note=biasing slightly toward recent motion instead of only all-time totals | sql=SELECT domain, name, comments_per_star_proxy, comment_count, distinct_commenters FROM ui_publication_directory WHERE inbound_recommendations BETWEEN 2 AND 150 ORDER BY comments_per_star_proxy DESC, distinct_commenters DESC LIMIT 25;
-- action_catalog_0996 | group=network | surface=bridge finder | prompt=Which publications seem to generate the most community energy per recommendation? | filter_note=only rows where description is not null when a UI card needs copy | ranking_note=secondary sort should prefer depth ascending for operational queues | ux_note=keeping enough metadata visible for a card-based interface | sql=SELECT domain, name, bridge_score, inbound_count, outbound_count FROM ui_recommendation_bridges ORDER BY bridge_score DESC, inbound_count DESC LIMIT 25;
-- action_catalog_0997 | group=community | surface=comment hubs | prompt=Which publications are good candidates for a people-also-read sidebar? | filter_note=only rows where comment_count >= 1 when the metric depends on discussion | ranking_note=default sort should stay descending by the main score with a stable domain tiebreaker | ux_note=staying useful even when comments tables are still sparse | sql=SELECT domain, name, comment_count, distinct_commenters, reply_ratio FROM ui_publication_directory ORDER BY comment_count DESC, distinct_commenters DESC, reply_ratio DESC LIMIT 25;
-- action_catalog_0998 | group=operations | surface=crawl triage | prompt=What should rank highly when the user wants vibrant discussion instead of pure graph centrality? | filter_note=only rows where distinct_inbound_sources >= 3 for stronger social proof | ranking_note=secondary sort should prefer recent_heat_score so stale giants do not always win | ux_note=making the answer feel more like a product leaderboard than a raw table dump | sql=SELECT domain, status, depth, has_publication_row, was_unfailed FROM ui_queue_health ORDER BY CASE status WHEN failed THEN 0 WHEN pending THEN 1 ELSE 2 END, depth ASC, domain ASC LIMIT 50;
-- action_catalog_0999 | group=search | surface=search results | prompt=Which rows would be easiest to explain in a friendly product UI? | filter_note=only rows where outbound_recommendations >= 1 to surface active recommenders | ranking_note=secondary sort should prefer distinct_commenters when discussion is the point | ux_note=so the UI can explain why the result ranked highly | sql=SELECT domain, name, description, star_proxy_count, recent_heat_score FROM ui_publication_search WHERE search_blob LIKE '%' || LOWER(:search_term) || '%' ORDER BY recent_heat_score DESC, star_proxy_count DESC LIMIT 25;
