-- action_catalog_1201 | group=stars | surface=home leaderboard | prompt=Which publications get a lot of stars and still look alive right now? | filter_note=no extra filter | ranking_note=default sort should stay descending by the main score with a stable domain tiebreaker | ux_note=prioritizing things a first-time user can understand instantly | sql=SELECT domain, name, star_proxy_count, distinct_inbound_sources, recent_heat_score FROM ui_publication_starboard ORDER BY star_proxy_count DESC, recent_heat_score DESC LIMIT 25;
-- action_catalog_1202 | group=heat | surface=trending rail | prompt=What should the homepage show if a user wants the safest high-signal starting points? | filter_note=only rows with star_proxy_count >= 5 when the action is star-oriented | ranking_note=secondary sort should prefer recent_heat_score so stale giants do not always win | ux_note=favoring approachable publications over edge-case operators | sql=SELECT domain, name, recent_heat_score, posts_last_30_days, comments_last_30_days FROM ui_publication_directory ORDER BY recent_heat_score DESC, inbound_recommendations DESC LIMIT 25;
-- action_catalog_1203 | group=discovery | surface=underrated shelf | prompt=Which publications deserve a hidden gems module because they outperform their hype? | filter_note=only rows with recent_heat_score > 0 for trending surfaces | ranking_note=secondary sort should prefer distinct_commenters when discussion is the point | ux_note=biasing slightly toward recent motion instead of only all-time totals | sql=SELECT domain, name, comments_per_star_proxy, comment_count, distinct_commenters FROM ui_publication_directory WHERE inbound_recommendations BETWEEN 2 AND 150 ORDER BY comments_per_star_proxy DESC, distinct_commenters DESC LIMIT 25;
-- action_catalog_1204 | group=network | surface=bridge finder | prompt=Which publications seem to generate the most community energy per recommendation? | filter_note=only rows where description is not null when a UI card needs copy | ranking_note=secondary sort should prefer bridge_score when discovery and navigation matter | ux_note=keeping enough metadata visible for a card-based interface | sql=SELECT domain, name, bridge_score, inbound_count, outbound_count FROM ui_recommendation_bridges ORDER BY bridge_score DESC, inbound_count DESC LIMIT 25;
-- action_catalog_1205 | group=community | surface=comment hubs | prompt=Which publications are good candidates for a people-also-read sidebar? | filter_note=only rows where comment_count >= 1 when the metric depends on discussion | ranking_note=secondary sort should prefer comments_per_star_proxy when hunting for underrated communities | ux_note=staying useful even when comments tables are still sparse | sql=SELECT domain, name, comment_count, distinct_commenters, reply_ratio FROM ui_publication_directory ORDER BY comment_count DESC, distinct_commenters DESC, reply_ratio DESC LIMIT 25;
