-- action_catalog_1662 | group=operations | surface=crawl triage | prompt=What should rank highly when the user wants vibrant discussion instead of pure graph centrality? | filter_note=only rows where distinct_inbound_sources >= 3 for stronger social proof | ranking_note=secondary sort should prefer depth ascending for operational queues | ux_note=making the answer feel more like a product leaderboard than a raw table dump | sql=SELECT domain, status, depth, has_publication_row, was_unfailed FROM ui_queue_health ORDER BY CASE status WHEN failed THEN 0 WHEN pending THEN 1 ELSE 2 END, depth ASC, domain ASC LIMIT 50;
-- action_catalog_1663 | group=search | surface=search results | prompt=Which rows would be easiest to explain in a friendly product UI? | filter_note=only rows where outbound_recommendations >= 1 to surface active recommenders | ranking_note=default sort should stay descending by the main score with a stable domain tiebreaker | ux_note=so the UI can explain why the result ranked highly | sql=SELECT domain, name, description, star_proxy_count, recent_heat_score FROM ui_publication_search WHERE search_blob LIKE '%' || LOWER(:search_term) || '%' ORDER BY recent_heat_score DESC, star_proxy_count DESC LIMIT 25;
-- action_catalog_1664 | group=threads | surface=reply explorer | prompt=What should power a quick filter that says top stars, hot now, underrated, or bridge builders? | filter_note=only rows whose domain does not start with www. for cleaner cards when helpful | ranking_note=secondary sort should prefer recent_heat_score so stale giants do not always win | ux_note=with columns selected to support chips, filters, sort toggles, and detail drawers | sql=SELECT publication_domain, publication_name, commenter_handle, parent_commenter_handle, body_length, commented_at FROM ui_comment_threads WHERE parent_comment_id IS NOT NULL ORDER BY commented_at DESC LIMIT 50;
